const binaryData = $input.first().binary?.ckimage;

if (!binaryData) {
  throw new Error("没有找到 binary property 'ckimage'，请检查上游节点是否正确输出 ckimage");
}

// 用 Buffer 读取图像（兼容 filesystem 模式）
const buffer = await this.helpers.getBinaryDataBuffer(0, 'ckimage');
const base64String = buffer.toString('base64');

// ────────────────────────────────────────────────
// 1. 解析原始分辨率（加强版 JPEG 扫描 + 边界保护）
let originalWidth = '未知';
let originalHeight = '未知';

try {
  const fileType = binaryData.mimeType || '';

  // PNG 解析（不变）
  if (fileType.includes('png') || buffer.toString('utf8', 0, 4) === '\x89PNG') {
    originalWidth  = buffer.readUInt32BE(16);
    originalHeight = buffer.readUInt32BE(20);
  } 
  // JPEG 加强扫描（顺序找 SOF 标记，防止跳过头或读错）
  else if (fileType.includes('jpeg') || fileType.includes('jpg') || (buffer[0] === 0xFF && buffer[1] === 0xD8)) {
    let i = 2;
    while (i < buffer.length - 10) {  // 留足空间避免越界
      if (buffer[i] !== 0xFF) {
        i++;
        continue;
      }

      const marker = buffer[i + 1];

      // 找到 SOF 标记（0xC0 ~ 0xCF 中的 Baseline/Progressive）
      if (marker >= 0xC0 && marker <= 0xCF && marker !== 0xC4 && marker !== 0xC8 && marker !== 0xCC) {
        // 跳过段长度 (2字节)
        // 字节 i+2 ~ i+3: 段长度
        // 字节 i+4: 数据精度 (1字节)
        // 字节 i+5 ~ i+6: 高度 (高字节在前)
        // 字节 i+7 ~ i+8: 宽度 (高字节在前)
        originalHeight = buffer.readUInt16BE(i + 5);
        originalWidth  = buffer.readUInt16BE(i + 7);
        break;
      }

      // 跳过当前段（防止无限循环）
      const segmentLength = buffer.readUInt16BE(i + 2);
      if (segmentLength < 2) break;  // 无效长度，防止死循环
      i += 2 + segmentLength;
    }
  }
} catch (e) {
  console.log("分辨率解析失败:", e.message);
}

// ────────────────────────────────────────────────
// 2. 把较短边放大到至少 1024（如果短边已 >=1024，则保持原尺寸）
let targetWidth = originalWidth;
let targetHeight = originalHeight;

if (originalWidth !== '未知' && originalHeight !== '未知') {
  const minSide = Math.min(originalWidth, originalHeight);

  // 只有短边 < 1024 时才放大
  if (minSide < 1024) {
    const scale = 1024 / minSide;
    targetWidth = Math.round(originalWidth * scale);
    targetHeight = Math.round(originalHeight * scale);
  }
  // 否则保持原尺寸
}

// ────────────────────────────────────────────────
// 3. 匹配最接近的预设比例（1:1、2:3、3:2、3:4、4:3、9:16、16:9、21:9）
let proportion = "1:1";

if (originalWidth !== '未知' && originalHeight !== '未知') {
  const ratio = originalWidth / originalHeight;

  const presets = [
    {name: "1:1",   r: 1.0},
    {name: "2:3",   r: 2/3},
    {name: "3:2",   r: 3/2},
    {name: "3:4",   r: 3/4},
    {name: "4:3",   r: 4/3},
    {name: "9:16",  r: 9/16},
    {name: "16:9",  r: 16/9},
    {name: "21:9",  r: 21/9}
  ];

  let minDiff = Infinity;
  for (const p of presets) {
    const diff = Math.abs(ratio - p.r);
    if (diff < minDiff) {
      minDiff = diff;
      proportion = p.name;
    }
  }
}

// ────────────────────────────────────────────────
// 输出结果（所有功能完整保留）
return [{
  json: {
    // 保留上游所有 json 数据
    ...$input.first().json,

    // 核心输出：base64
    base64: base64String,
    data_uri: `data:${binaryData.mimeType || 'image/png'};base64,${base64String}`,

    // 原有文件信息
    originalFileName: binaryData.fileName || 'unnamed.png',
    mimeType: binaryData.mimeType || 'image/png',
    fileSizeBytes: binaryData.fileSize || 'unknown',

    // 原始分辨率
    originalResolution: {
      width: originalWidth,
      height: originalHeight,
      display: originalWidth !== '未知' ? `${originalWidth} × ${originalHeight}` : '无法解析'
    },

    // 目标分辨率（短边至少 1024，已大于则保持原尺寸）
    targetResolution: {
      width: targetWidth,
      height: targetHeight,
      display: `${targetWidth} × ${targetHeight}`
    },

    // 最接近的预设比例
    proportion: proportion
  }
}];

